#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int weights[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &weights[i]);
    }
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += weights[i];
    }
    if (sum % n != 0) {
        printf("-1\n");
    } else {
        int target = sum / n;
        int dp[n + 1][target + 1];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= target; j++) {
                dp[i][j] = 0;
            }
        }
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= target; j++) {
                if (weights[i - 1] <= j) {
                    dp[i][j] = dp[i - 1][j] + dp[i - 1][j - weights[i - 1]];
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }
        printf("%d\n", dp[n][target]);
    }
    return 0;
}

